251		RTLIL::SigSpec handle_call(const ast::CallExpression &call)
252		{
253			RTLIL::SigSpec ret;
254	
255			require(call, !call.isSystemCall());
256			auto subroutine = std::get<0>(call.subroutine);
257			auto arg_symbols = subroutine->getArguments();
258	
259			std::vector<RTLIL::SigSpec> arg_in, arg_out;
260	
261			for (int i = 0; i < (int)arg_symbols.size(); i++) {
262				const ast::Expression *arg = call.arguments()[i];
263				auto dir = arg_symbols[i]->direction;
264	
265				if (dir == ast::ArgumentDirection::In || dir == ast::ArgumentDirection::InOut)
266					arg_in.push_back(eval(*arg));
267				else
268					arg_in.push_back({});
269			}
270	
271			slang::SourceLocation loc = call.sourceRange.start();
272	
273			{
274				EnterAutomaticScopeGuard scope_guard(eval, subroutine);
275	
276				for (auto &member : subroutine->members())
277					if (ast::VariableSymbol::isKind(member.kind)) {
278						auto &var = member.as<ast::VariableSymbol>();
279	
280						if (var.kind == ast::SymbolKind::FormalArgument ||
281								var.flags.has(ast::VariableFlags::CompilerGenerated))
282							var.visit(*this);
283					}
284	
285				for (int i = 0; i < (int)arg_symbols.size(); i++) {
286					auto dir = arg_symbols[i]->direction;
287					if (dir == ast::ArgumentDirection::In || dir == ast::ArgumentDirection::InOut)
288						context.do_simple_assign(loc, eval.variable(*arg_symbols[i]), arg_in[i], true);
289				}
290	
291				{
292					RegisterEscapeConstructGuard escape_guard(
293							context, EscapeConstructKind::FunctionBody, subroutine);
294					subroutine->getBody().visit(*this);
295				}
296	
297				for (int i = 0; i < (int)arg_symbols.size(); i++) {
298					auto dir = arg_symbols[i]->direction;
299					if (dir == ast::ArgumentDirection::Out || dir == ast::ArgumentDirection::InOut)
300						arg_out.push_back(context.substitute_rvalue(eval.variable(*arg_symbols[i])));
301					else
302						arg_out.push_back({});
303				}
304	
305				if (subroutine->returnValVar)
306					ret = context.substitute_rvalue(eval.variable(*subroutine->returnValVar));
307			}
308	
309			for (int i = 0; i < (int)arg_symbols.size(); i++) {
310				const ast::Expression *arg = call.arguments()[i];
311				auto dir = arg_symbols[i]->direction;
312	
313				if (dir == ast::ArgumentDirection::Out || dir == ast::ArgumentDirection::InOut)
314					context.assign_rvalue(arg->as<ast::AssignmentExpression>(), arg_out[i]);
315			}
316	
317			return ret;
318		}
